    16→
    17→  it('does not submit if there are errors', async () => {
    18→    const onSubmit = spy();
    19→
    20→    const { user } = render(
    21→      <Form onSubmit={onSubmit}>
    22→        <Field.Root>
    23→          <Field.Control required />
    24→          <Field.Error data-testid="error" />
    25→        </Field.Root>
    26→        <button>Submit</button>
    27→      </Form>,
    28→    );
    29→
    30→    const submit = screen.getByRole('button');
    31→
    32→    await user.click(submit);
    33→
    34→    expect(screen.getByTestId('error')).not.to.equal(null);
    35→    expect(onSubmit.called).to.equal(false);
    36→  });
    37→
