      expect(screen.getByTestId('form')).not.to.have.attribute('novalidate');
    });
  });

  describe('dynamically adding/removing fields', () => {
    it('should handle form submission after dynamically removing a field', async () => {
      function App() {
        const [showField, setShowField] = React.useState(true);
        return (
          <Form>
            <Field.Root>
              <Field.Control required data-testid="field1" />
            </Field.Root>
            {showField && (
              <Field.Root>
                <Field.Control data-testid="field2" />
              </Field.Root>
            )}
            <button type="button" onClick={() => setShowField(!showField)} data-testid="toggle">
              Toggle
            </button>
            <button type="submit" data-testid="submit">
              Submit
            </button>
          </Form>
        );
      }

      const { user } = render(<App />);

      const toggle = screen.getByTestId('toggle');
      const submit = screen.getByTestId('submit');

      // Remove the field
      await user.click(toggle);
      // Add it back
      await user.click(toggle);
      // Remove again
      await user.click(toggle);

      // Try to submit - this should not throw an error
      await user.click(submit);

      // The form should still work and focus the first invalid field
      const field1 = screen.getByTestId('field1');
      expect(field1).toHaveFocus();
    });

    it('should handle form submission after dynamically adding a field', async () => {
      function App() {
        const [showField, setShowField] = React.useState(false);
        return (
          <Form>
            <Field.Root>
              <Field.Control required data-testid="field1" />
            </Field.Root>
            {showField && (
              <Field.Root>
                <Field.Control required data-testid="field2" />
              </Field.Root>
            )}
            <button type="button" onClick={() => setShowField(!showField)} data-testid="toggle">
              Toggle
            </button>
            <button type="submit" data-testid="submit">
              Submit
            </button>
          </Form>
        );
      }

      const { user } = render(<App />);

      const toggle = screen.getByTestId('toggle');
      const submit = screen.getByTestId('submit');

      // Add the field
      await user.click(toggle);
      // Try to submit - this should not throw an error
      await user.click(submit);

      // The form should focus the first invalid field
      const field1 = screen.getByTestId('field1');
      expect(field1).toHaveFocus();
    });
  });
});

