// Register/unregister field on mount/unmount
useModernLayoutEffect(() => {
  if (!enabled || !id) {
    return;
  }

  // Initial registration with placeholder data
  formRef.current.fields.set(id, {
    controlRef,
    validityData: getCombinedFieldValidityData(validityData, invalid),
    validate() {
      let nextValue = value;
      if (nextValue === undefined) {
        nextValue = getValueRef.current?.();
      }

      markedDirtyRef.current = true;
      // Synchronously update the validity state so the submit event can be prevented.
      ReactDOM.flushSync(() => commitValidation(nextValue));
    },
    getValueRef,
    name,
  });

  return () => {
    formRef.current.fields.delete(id);
  };
  // Only run on mount/unmount or when id/enabled changes
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [enabled, id]);

// Update field data when dependencies change
useModernLayoutEffect(() => {
  if (!enabled || !id) {
    return;
  }

  const field = formRef.current.fields.get(id);
  if (field) {
    // Update the existing field entry without removing/re-adding
    field.controlRef = controlRef;
    field.validityData = getCombinedFieldValidityData(validityData, invalid);
    field.validate = () => {
      let nextValue = value;
      if (nextValue === undefined) {
        nextValue = getValueRef.current?.();
      }

      markedDirtyRef.current = true;
      ReactDOM.flushSync(() => commitValidation(nextValue));
    };
    field.getValueRef = getValueRef;
    field.name = name;
  }
}, [
  commitValidation,
  controlRef,
  enabled,
  formRef,
  getValueRef,
  id,
  invalid,
  markedDirtyRef,
  name,
  validityData,
  value,
]);

